
const SHEET_ID = '16aLq8UzMfWs78ewzGCmKvM_7DjL5IO7MqUce0BPb9SE';
const API_KEY  = 'AIzaSyCDyW7kus9hKlENwRBn7txq-RoftQtv7Hw';
const ABA      = 'novo';

let selecionado = null, qtd = 1, dadosCache = null;

// Template PNG será injetado aqui como base64
const TEMPLATE_BG = 'data:image/png;base64,';

function fmt(s) {
  if (!s) return '';
  const exc = ['de','da','do','dos','das','e','em'];
  return s.trim().toLowerCase().split(/\s+/).map((w,i) =>
    exc.includes(w) && i > 0 ? w : w.charAt(0).toUpperCase() + w.slice(1)
  ).join(' ');
}
function fmtBairro(b) {
  const l = b.toLowerCase().trim();
  if (l.includes('barra da tijuca')) return 'Barra';
  if (l.includes('recreio')) return 'Recreio';
  return fmt(b);
}
async function carregarDados() {
  if (dadosCache) return dadosCache;
  const url = `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values/${ABA}!A:M?key=${API_KEY}`;
  const res = await fetch(url);
  if (!res.ok) { const e = await res.json(); throw new Error(e.error?.message || 'Erro na API do Google'); }
  dadosCache = (await res.json()).values || [];
  return dadosCache;
}
function parseLinha(row, i) {
  const g = n => String(row[n] || '').trim();
  const pets = g(1).split(/,| e | E |&|\+| \/ /).map(p => fmt(p.trim())).filter(Boolean);
  if (!pets.length) pets.push('Pet');
  return { index:i, tutor:fmt(g(0)), pets, bairro:fmtBairro(g(12)), rua:fmt(g(9)), numero:g(10), comp:fmt(g(11)) };
}
async function buscar() {
  const termo = document.getElementById('inp').value.trim();
  const area = document.getElementById('area-resultado');
  const btn = document.getElementById('btnBuscar');
  if (!termo) return;
  area.innerHTML = '<div class="status"><div class="spin-wrap"><div class="spinner"></div> Farejando dados...</div></div>';
  btn.disabled = true;
  try {
    const rows = await carregarDados();
    const t = termo.toLowerCase();
    const found = rows.slice(1).map((r,i) => parseLinha(r,i+1))
      .filter(r => r.tutor.toLowerCase().includes(t) || r.pets.some(p => p.toLowerCase().includes(t)));
    btn.disabled = false;
    if (!found.length) { area.innerHTML = '<div class="status">Nenhum resultado para "'+termo+'"</div>'; return; }
    window._encontrados = found;
    let html = '<div class="results-label">'+found.length+' resultado'+(found.length>1?'s':'')+' — clique no pet:</div>';
    found.forEach((r,i) => {
      html += `<div class="result-card"><div class="result-name">${r.tutor}</div><div class="result-addr">📍 ${r.bairro} · ${r.rua}${r.numero?', '+r.numero:''}${r.comp?' – '+r.comp:''}</div><div class="pets-row">`;
      r.pets.forEach(p => { html += `<button class="pet-chip" onclick="selecionar(${i},'${p.replace(/'/g,"\\'")}')">🐾 ${p}</button>`; });
      html += '</div></div>';
    });
    area.innerHTML = html;
  } catch(e) {
    btn.disabled = false;
    let msgExtra = '';
    if (e.message === 'Failed to fetch' || e.message.includes('fetch')) {
      msgExtra = `
        <div class="aviso-planilha">
          <strong>Como resolver:</strong><br>
          1. Abra a planilha no Google Sheets<br>
          2. Clique em <strong>Compartilhar</strong> (canto superior direito)<br>
          3. Mude para <strong>"Qualquer pessoa com o link pode ver"</strong><br>
          4. Salve e tente buscar novamente
        </div>`;
    }
    area.innerHTML = `<div class="erro">Erro: ${e.message}</div>${msgExtra}`;
  }
}
function selecionar(i, pet) {
  selecionado = { ...window._encontrados[i], pet };
  qtd = 1;
  document.getElementById('c-pet').textContent = pet;
  document.getElementById('c-tutor').textContent = selecionado.tutor;
  const end = selecionado.comp ? `${selecionado.rua}, ${selecionado.numero} - ${selecionado.comp}` : `${selecionado.rua}, ${selecionado.numero}`;
  document.getElementById('c-addr').textContent = end;
  document.getElementById('qtd-display').textContent = '1';
  document.getElementById('tela-busca').style.display = 'none';
  document.getElementById('tela-confirmar').style.display = 'block';
}
function mudaQtd(d) { qtd = Math.max(1,qtd+d); document.getElementById('qtd-display').textContent = qtd; }
function voltarBusca() { document.getElementById('tela-confirmar').style.display='none'; document.getElementById('tela-busca').style.display='block'; }

function gerar() {
  const btn = document.getElementById('btnGerar');
  btn.disabled = true; btn.textContent = 'Gerando...';
  setTimeout(() => {
    try {
      const { jsPDF } = window.jspdf;
      const doc = new jsPDF({ orientation:'landscape', unit:'mm', format:[100,150] });
      const W=150, H=100, s=selecionado;
      const end = s.comp ? `${s.rua}, ${s.numero} - ${s.comp}` : `${s.rua}, ${s.numero}`;

      // ── Fundo: PNG do template original ──
      doc.addImage(TEMPLATE_BG, 'PNG', 0, 0, W, H);

      // Retângulos brancos para cobrir os placeholders do template
      const wb = () => doc.setFillColor(255, 255, 255);

      // ── {{bairro}} → canto superior direito ──
      wb(); doc.rect(93, 3, 55, 17, 'F');
      doc.setFontSize(16); doc.setFont('helvetica','bold'); doc.setTextColor(232,80,10);
      doc.text(s.bairro, W-5, 15, { align:'right' });

      // ── {{tutor}} → abaixo de "Responsável" ──
      wb(); doc.rect(23, 35, 110, 13, 'F');
      doc.setTextColor(20,20,20); doc.setFontSize(11); doc.setFont('helvetica','bold');
      const tutorLines = doc.splitTextToSize(s.tutor, W-35);
      doc.text(tutorLines, 26, 43);

      // ── {{endereço}} → abaixo de "Entrega em:" ──
      wb(); doc.rect(23, 56, 115, 14, 'F');
      doc.setTextColor(20,20,20); doc.setFontSize(10); doc.setFont('helvetica','bold');
      const endLines = doc.splitTextToSize(end, W-35);
      doc.text(endLines, 26, 64);

      // ── {{qtd}} Pacotes → canto inferior esquerdo ──
      wb(); doc.rect(17, 80, 50, 14, 'F');
      doc.setTextColor(20,20,20); doc.setFontSize(12); doc.setFont('helvetica','bold');
      doc.text(String(qtd) + ' Pacotes', 20, 90);

      // ── {{nome_pet}} → canto inferior direito ──
      wb(); doc.rect(108, 80, 40, 14, 'F');
      doc.setTextColor(20,20,20); doc.setFontSize(12); doc.setFont('helvetica','bold');
      doc.text(s.pet, W-5, 90, { align:'right' });
      // -- Nome do arquivo com data/hora ──
      const agora = new Date();
      const dataHora = `${agora.getDate().toString().padStart(2,'0')}-${(agora.getMonth()+1).toString().padStart(2,'0')}-${agora.getFullYear()}_${agora.getHours().toString().padStart(2,'0')}h${agora.getMinutes().toString().padStart(2,'0')}`;
      doc.save(`Etiqueta - ${s.tutor} - ${s.pet} - ${dataHora}.pdf`);

      btn.disabled = false; btn.textContent = 'Baixar Etiqueta PDF';
      document.getElementById('tela-confirmar').style.display = 'none';
      document.getElementById('done-msg').textContent = `Etiqueta de ${s.pet} (${s.tutor}) gerada!`;
      document.getElementById('tela-feito').style.display = 'block';
    } catch(e) {
      btn.disabled = false; btn.textContent = 'Baixar Etiqueta PDF';
      alert('Erro ao gerar PDF: ' + e.message);
    }
  }, 300);
}

function reiniciar() {
  selecionado = null; qtd = 1;
  document.getElementById('tela-feito').style.display = 'none';
  document.getElementById('area-resultado').innerHTML = '';
  document.getElementById('inp').value = '';
  document.getElementById('tela-busca').style.display = 'block';
  document.getElementById('inp').focus();
}

document.getElementById('inp').addEventListener('keydown', e => { if(e.key==='Enter') buscar(); });

